rego_examples:
# WRE: only surface recommendations the user is eligible for and that pass governance
package wre.recommend

default allow = false

allow {
  input.user.entitlements[_] == input.workflow.requiredEntitlement
  input.workflow.riskTier != "prohibited"
  not blocked
}

blocked {
  input.workflow.riskTier == "high"
  not input.user.highRiskApproved
}

# Sentinel: model promotion requires independent validation + (high-risk) Annex IV
package sentinel.promotion

default allow = false
allow {
  input.action == "promote"
  input.model.validation.independence == true
  input.model.validation.rating == "satisfactory"
  annex_ok
}
annex_ok { not input.model.highRisk }
annex_ok { input.model.highRisk; input.model.annexIV.completeness >= 0.98 }
